new_cal = "function renderRouteCalendar(){ if(!els.routeCalendar) return; const routes=sortedRoutes(state.routes); if(els.routeAgendaLabel) els.routeAgendaLabel.textContent=(els.owner&&els.owner.value)?'Agenda anual':'Período'; if(!routes.length){ els.routeCalendar.innerHTML='<div class=\"rp-chart-empty\">Sem rotas para mostrar em calendário.</div>'; return; } const months=availableRouteMonths(routes); const selectedRoute=(state.selectedRouteId && routes.find(r=>String(r.id)===String(state.selectedRouteId))) || null; if(selectedRoute && routeMonthKey(selectedRoute)) state.routeCalendarMonth=routeMonthKey(selectedRoute); if(!state.routeCalendarMonth || months.indexOf(state.routeCalendarMonth)<0) state.routeCalendarMonth=months[0]||''; const month=state.routeCalendarMonth; const monthRoutes=routes.filter(r=>routeMonthKey(r)===month); const [year,mon]=month.split('-').map(n=>parseInt(n,10)); const first=new Date(year,mon-1,1); const daysInMonth=new Date(year,mon,0).getDate(); const offset=(first.getDay()+6)%7; const byDate=new Map(); monthRoutes.forEach(r=>{ const d=String(r.date||''); if(!byDate.has(d)) byDate.set(d,[]); byDate.get(d).push(r); }); const cells=[]; for(let i=0;i<offset;i++) cells.push('<div class=\"rp-day-empty\"></div>'); for(let day=1; day<=daysInMonth; day++){ const date=month+'-'+String(day).padStart(2,'0'); const items=byDate.get(date)||[]; if(!items.length){ cells.push('<div class=\"rp-day-empty\"></div>'); continue; } const km=items.reduce((n,r)=>n+routeKm(r),0); const stops=items.reduce((n,r)=>n+routeStops(r),0); const active=items.some(r=>String(r.id)===String(state.selectedRouteId)); cells.push(`<button type=\"button\" class=\"rp-day-chip ${active?'active':''}\" data-open-route=\"${esc(items[0].id)}\" title=\"${esc(items.length+' rota(s), '+fmtKm(km)+', '+stops+' PDVs')}\"><span>${day}</span><small>${items.length} rota${items.length===1?'':'s'}<br>${fmtKm(km)} · ${stops} PDVs</small></button>`); } const idx=months.indexOf(month); const monthOptions=months.map(m=>`<option value=\"${esc(m)}\" ${m===month?'selected':''}>${esc(monthLabel(m))}</option>`).join(''); els.routeCalendar.innerHTML=`<div class=\"rp-calendar-controls\"><button type=\"button\" class=\"rp-small\" data-cal-prev ${idx<=0?'disabled':''}>Anterior</button><select id=\"rpcp-route-month\">${monthOptions}</select><button type=\"button\" class=\"rp-small\" data-cal-next ${idx>=months.length-1?'disabled':''}>Seguinte</button></div><div class=\"rp-month-card\"><h5>${esc(monthLabel(month))} · ${monthRoutes.length} rota${monthRoutes.length===1?'':'s'}</h5><div class=\"rp-weekdays\"><div class=\"rp-weekday\">Seg</div><div class=\"rp-weekday\">Ter</div><div class=\"rp-weekday\">Qua</div><div class=\"rp-weekday\">Qui</div><div class=\"rp-weekday\">Sex</div><div class=\"rp-weekday\">Sáb</div><div class=\"rp-weekday\">Dom</div></div><div class=\"rp-month-days\">${cells.join('')}</div></div>`; els.routeCalendar.querySelectorAll('[data-open-route]').forEach(btn=>btn.addEventListener('click',()=>openRouteFromAgenda(btn.dataset.openRoute))); const monthSel=els.routeCalendar.querySelector('#rpcp-route-month'); if(monthSel) monthSel.addEventListener('change',()=>{ state.routeCalendarMonth=monthSel.value||month; state.routeListPage=1; renderRouteCalendar(); renderRouteList(); }); els.routeCalendar.querySelector('[data-cal-prev]')?.addEventListener('click',()=>{ if(idx>0){ state.routeCalendarMonth=months[idx-1]; state.routeListPage=1; renderRouteCalendar(); renderRouteList(); } }); els.routeCalendar.querySelector('[data-cal-next]')?.addEventListener('click',()=>{ if(idx<months.length-1){ state.routeCalendarMonth=months[idx+1]; state.routeListPage=1; renderRouteCalendar(); renderRouteList(); } }); }"
